with open('data/output/benchmark/task_a/REDACTED.jsonl') as f:
    lines = [json.loads(l) for l in f]

state_re = re.compile(r'\[STATE:\s*(\w+)\s*(?:->|→)\s*(\w+)\]')
tool_re = re.compile(r'<tool_call>(.*?)</tool_call>', re.S)
issues = []
for s in lines:
    cid = s['conversation_id']
    g = s['workflow_graph']
    gt = [(t['from'],t['to']) for t in s['ground_truth']['state_sequence']]
    ann = []
    for m in s['messages']:
        if m['role']=='assistant':
            ann += state_re.findall(m['content'])
    if ann != gt:
        issues.append(f'{cid}: STATE-ann {ann} != gt {gt}')
    # terminal coherence
    if gt and gt[-1][1] != s['ground_truth']['terminal_state']:
        issues.append(f'{cid}: last gt transition->{gt[-1][1]} != terminal {s[\"ground_truth\"][\"terminal_state\"]}')
    # all annotated states exist in graph states
    gstates = set(g['states'])
    for f_,t_ in ann:
        if f_ not in gstates or t_ not in gstates:
            issues.append(f'{cid}: annotated state {f_}/{t_} not in graph states')
    # each annotated transition must be a valid graph edge OR self-loop
    edges = {(t['from'],t['to']) for t in g['transitions']}
    for f_,t_ in ann:
        if f_!=t_ and (f_,t_) not in edges:
            issues.append(f'{cid}: transition {f_}->{t_} not a graph edge')
    # tool_call count vs ground_truth.tool_calls
    tc_msgs = sum(len(tool_re.findall(m['content'])) for m in s['messages'])
    if tc_msgs != len(s['ground_truth']['tool_calls']):
