import json, re, collections
fn='data/output/benchmark/task_a/REDACTED.jsonl'
with open(fn) as f:
    lines=[json.loads(l) for l in f]

state_re=re.compile(r'\[STATE:\s*(\w+)\s*(?:->|→)\s*(\w+)\]')
tool_re=re.compile(r'<tool_call>(.*?)</tool_call>', re.S)
issues=[]
arrow=collections.Counter()
for s in lines:
    cid=s['conversation_id']; g=s['workflow_graph']
    gt=[(t['from'],t['to']) for t in s['ground_truth']['state_sequence']]
    ann=[]
    for m in s['messages']:
        if m['role']=='assistant':
            for a in re.findall(r'\[STATE:[^\]]*\]', m['content']):
                arrow['ascii' if '->' in a else 'uni' if '→' in a else 'other']+=1
            ann+=state_re.findall(m['content'])
    if ann!=gt: issues.append(f'{cid}: STATE-ann != gt | ann={ann} gt={gt}')
    if gt and gt[-1][1]!=s['ground_truth']['terminal_state']:
        issues.append(f'{cid}: last->{gt[-1][1]} != terminal {s[\"ground_truth\"][\"terminal_state\"]}')
    if gt and gt[0][0]!=g['initial']:
        issues.append(f'{cid}: first from {gt[0][0]} != initial {g[\"initial\"]}')
    gstates=set(g['states']); edges={(t['from'],t['to']) for t in g['transitions']}
    for f_,t_ in ann:
        if f_ not in gstates or t_ not in gstates: issues.append(f'{cid}: state {f_}/{t_} not in graph')
        elif f_!=t_ and (f_,t_) not in edges: issues.append(f'{cid}: edge {f_}->{t_} not in graph')
    # tool call validity + schema membership + count vs gt
    schema_names={t.get('name') or t.get('function',{}).get('name') for t in s['tool_schemas']}
    nc=0
    for m in s['messages']:
        for raw in tool_re.findall(m['content']):
            nc+=1
            try: d=json.loads(raw.strip())
            except Exception: issues.append(f'{cid}: bad tool JSON {raw[:50]!r}'); continue
            if d.get('name') not in schema_names: issues.append(f'{cid}: tool {d.get(\"name\")!r} not in schemas')
    if nc!=len(s['ground_truth']['tool_calls']): issues.append(f'{cid}: msg calls {nc} != gt calls {len(s[\"ground_truth\"][\"tool_calls\"])}')
    # role sequencing
    roles=[m['role'] for m in s['messages']]
    if roles[0]!='system': issues.append(f'{cid}: msg0 not system')
    for i,r in enumerate(roles):
        if r=='tool' and (i==0 or roles[i-1]!='assistant'): issues.append(f'{cid}: tool not after assistant @ {i}')
    for i in range(1,len(roles)):
        if roles[i]=='user' and roles[i-1]=='user': issues.append(f'{cid}: consecutive user @ {i}')
    # initiator shape
    exp='assistant' if s['conversation_initiator']=='agent' else 'user'
    if roles[1]!=exp: issues.append(f'{cid}: initiator {s[\"conversation_initiator\"]} but msg1={roles[1]}')
    # chain_depth field
    if s['chain_depth']!=1: issues.append(f'{cid}: chain_depth {s[\"chain_depth\"]} != 1 (L2)')

print('arrow styles:', dict(arrow))
print('TOTAL ISSUES:', len(issues))
for x in issues: print(' -', x)
"

